('7d63a3bf-b13d-42f6-9bbc-a01a0eed5b1b','Ög 64','B 889|L 1183',58.3722,15.0048,'trikiaʀ + risþu + stin + þisi + aft + krib kilta + sin + lufi + rist + runaʀ + þisʀ + iuta + sunu','Drengir reistu stein þenna ept "Greip, gilda sinn, "Lófi reist rúnar þessar, "Júta son.',NULL,'Valiant men raised this stone in memory of Greipr, their guild-brother - Lófi carved these runes - Júti''s son.',NULL,'Salberger (1990c:26ff) tolkar slutet som ''Jutes duktige son''.','Runsten','Sten','Östergötland','Sweden')
) as v(id, signum, alt, lat, lng, translit, norm, tsv, ten, dating, notes, otype, material, landscape, country)
where not exists (
  select 1 from public.runic_inscriptions ri
  where lower(regexp_replace(ri.signum,'\s+',' ','g')) = lower(regexp_replace(v.signum,'\s+',' ','g'))
)
on conflict (id) do nothing;
